ValidationRule.errorConditionFormula:
AND(
  NOT(ISNEW()),
  NOT(ISBLANK(Ward__c)),
  IF(ISNUMBER(Name), VALUE(Name) > Ward__r.Capacity__c,
    VALUE(
      IF(AND(LEN(Name) >= 4, CONTAINS("0123456789", MID(Name, LEN(Name) - 3, 1))), RIGHT(Name, 4),
        IF(AND(LEN(Name) >= 3, CONTAINS("0123456789", MID(Name, LEN(Name) - 2, 1))), RIGHT(Name, 3),
          IF(AND(LEN(Name) >= 2, CONTAINS("0123456789", MID(Name, LEN(Name) - 1, 1))), RIGHT(Name, 2),
            IF(AND(LEN(Name) >= 1, CONTAINS("0123456789", RIGHT(Name, 1))), RIGHT(Name, 1),
              "0"
            )
          )
        )
      )
    ) > Ward__r.Capacity__c
  )
)
